// ONE™ Lead Sync Logic
const sheetRows = $('קריאת גיליון לידים').all();
const existingLeads = $('שליפת לידים קיימים').first().json.body || [];
const existingEmails = new Set(existingLeads.map(l => (l.email || '').toLowerCase().trim()));
const existingPhones = new Set(existingLeads.map(l => cleanPhone(l.phone)));

function cleanPhone(raw) {
  if (!raw) return null;
  let phone = raw.toString().replace(/[\s\-\(\)]/g, '');
  if (phone.startsWith('+972')) phone = '0' + phone.slice(4);
  if (phone.length === 9 && !phone.startsWith('0')) phone = '0' + phone;
  return phone.length >= 9 && phone.length <= 11 ? phone : null;
}

const statusMap = {
  'חדש': 'new',
  'צרך תוכן': 'consumed_content',
  'ביצע אינטראקציה': 'engaged',
  'הגיש בקשה': 'applied',
  'מתאים': 'qualified',
  'בקליטה': 'onboarding',
  'לקוח פעיל': 'active_client',
  'סיים': 'completed',
  'אבוד': 'lost'
};

const sourceMap = {
  'אינסטגרם': 'instagram',
  'לינקדאין': 'linkedin',
  'יוטיוב': 'youtube',
  'קמפיין': 'campaign',
  'אורגני': 'organic',
  'הפניה': 'referral',
  'תוכן': 'content',
  'וובינר': 'webinar',
  'סקול': 'skool'
};

const testEmails = ['test@test.com', 'ben@test.com'];

const newLeads = [];
const newCustomers = [];
const newTransactions = [];

for (const row of sheetRows) {
  const d = row.json;
  const name = (d['שם מלא'] || d['שם'] || '').trim();
  const email = (d['מייל'] || d['אימייל'] || '').toLowerCase().trim();
  const phone = cleanPhone(d['טלפון'] || '');
  const statusHeb = (d['סטטוס'] || d['שלב'] || 'חדש').trim();
  const sourceHeb = (d['מקור'] || 'אורגני').trim();
  const amount = parseFloat(d['סכום'] || d['סכום עסקה'] || '0') || 0;
  const igHandle = (d['אינסטגרם'] || d['instagram'] || '').trim();
  const painPoints = (d['כאב'] || d['בעיה'] || '').trim();
  const howFound = (d['איך הגיע'] || '').trim();
  const notes = (d['הערות'] || '').trim();
  const dateStr = d['תאריך'] || d['תאריך יצירה'] || '';

  // Skip empty/test/duplicate
  if (!name || name.length < 2) continue;
  if (testEmails.includes(email)) continue;
  if (email && existingEmails.has(email)) continue;
  if (phone && existingPhones.has(phone)) continue;

  const status = statusMap[statusHeb] || 'new';
  const source = sourceMap[sourceHeb] || 'other';

  let createdAt = null;
  if (dateStr) {
    const parts = dateStr.split('/');
    if (parts.length === 3) {
      createdAt = new Date(parts[2], parts[1] - 1, parts[0]).toISOString();
    }
  }

  const lead = {
    name, email: email || null, phone: phone || null,
    current_status: status, source,
    instagram_handle: igHandle || null,
    pain_points: painPoints || null,
    how_found_us: howFound || null,
    interest_program: 'one_core'
  };
  if (createdAt) lead.created_at = createdAt;
  newLeads.push(lead);

  // If paid → create customer + transaction
  if (amount > 0 || status === 'active_client') {
    newCustomers.push({
      name, email: email || null, phone: phone || null,
      program: 'one_core', total_paid: amount, status: 'active',
      mentor: 'בן'
    });
    if (amount > 0) {
      newTransactions.push({
        program: 'one_core', amount, status: 'completed',
        payment_method: 'other'
      });
    }
  }
}

return [{
  json: {
    newLeads, newCustomers, newTransactions,
    counts: {
      leads: newLeads.length,
      customers: newCustomers.length,
      transactions: newTransactions.length
    }
  }
}];
